INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Grammar and style reports$q$, $q$Over 20 in-depth reports covering grammar, style, sentence structure, and clarity, each with plain-language explanations rather than silent auto-corrections.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Readability report$q$, $q$Scores and highlights sentences and paragraphs that may be hard to read, helping writers simplify dense or convoluted prose.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Repeats and overused words$q$, $q$Flags repeated words and phrases across a document to help vary word choice and tighten prose.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Pacing and dialogue reports$q$, $q$Fiction-specific analysis of narrative pacing and dialogue tags, aimed at novelists refining manuscript-length work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Rephrase (AI rewriting)$q$, $q$AI-generated sentence rewrites in different tones and styles, letting writers pick an alternative phrasing with one click.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Spark AI$q$, $q$A generative AI assistant for brainstorming, outlining, and drafting content within the editor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Author style comparison$q$, $q$Compares a writer's style metrics against a set of published fiction authors to benchmark pacing and sentence variety.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Integrations and Desktop Everywhere$q$, $q$Works inside Microsoft Word, Google Docs, Scrivener, and other apps via desktop integration, plus browser extensions for Chrome, Firefox, and Edge.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Custom style guide$q$, $q$Lets Premium users define custom terminology, spelling preferences, and style rules enforced across documents.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Depth of writing analysis goes well beyond basic grammar and spelling checks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Strong fit for long-form fiction with pacing, dialogue, and author-comparison reports$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Free plan and one-time lifetime purchase options give flexible entry points$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Wide range of app and browser integrations, including Scrivener support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Explanations behind suggestions help writers improve skills over time, not just fix one document$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$English-only support, with no other languages currently checked$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$No native iOS or Android apps, only a mobile-accessible web editor$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Free plan's 500-word limit per check makes it impractical for full manuscripts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Large number of reports can feel overwhelming to new or casual users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Premium Pro's community and workshop perks add cost that non-fiction writers may not use$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Is ProWritingAid free to use?$q$, $q$Yes, there is a free plan with grammar, spelling, and punctuation checks, a 500-word limit per document, and limited daily use of AI rephrasing and Spark features. Full access to all reports requires a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Does ProWritingAid support languages other than English?$q$, $q$No, ProWritingAid currently checks only English text, though it supports US, UK, Canadian, and Australian English dialects.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Can I use ProWritingAid inside Microsoft Word or Google Docs?$q$, $q$Yes, ProWritingAid integrates with Microsoft Word, Google Docs, Scrivener, and other apps through its Desktop Everywhere feature and browser extensions for Chrome, Firefox, and Edge.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Is there a lifetime plan for ProWritingAid?$q$, $q$Yes, ProWritingAid offers one-time lifetime purchase options for both its Premium and Premium Pro tiers, in addition to monthly and annual subscriptions.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$How is ProWritingAid different from Grammarly?$q$, $q$ProWritingAid offers a larger number of specialized reports, including fiction-focused tools like pacing and dialogue analysis, and leans toward long-form authors, while Grammarly focuses more heavily on everyday and business writing.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Editing a novel manuscript$q$, $q$Authors run full manuscripts through pacing, dialogue, repeats, and author-comparison reports to self-edit before querying agents or publishing.$q$, $q$Fiction writers and novelists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Polishing blog posts and articles$q$, $q$Bloggers and content writers use readability and style reports to tighten prose and match a target reading level before publishing.$q$, $q$Bloggers and content marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Improving academic writing$q$, $q$Students use grammar and clarity reports to catch structural issues and improve sentence-level writing quality in essays and papers.$q$, $q$Students and academic writers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Refining business documents$q$, $q$Professionals use style and grammar checks inside Word or the browser extension to clean up reports, emails, and proposals.$q$, $q$Business professionals$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["500-word limit per check","Limited daily report runs","Limited daily Rephrase and Spark AI use","Grammar, spelling, and punctuation checks","Word Explorer and thesaurus"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Premium$q$, $q$$10-30/month depending on billing term, or $399 lifetime$q$, $q$Monthly, annual, or one-time lifetime$q$, $q$["Unlimited word count and document storage","Unlimited report runs and Rephrase use","Custom style guide and Snippets","Author style comparison","Citations and collaboration tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$Premium Pro$q$, $q$$12-36/month depending on billing term, or $699 lifetime$q$, $q$Monthly, annual, or one-time lifetime$q$, $q$["Everything in Premium","More daily Spark AI and Chapter Critique uses","Higher discounts on Story Credits","Live workshops with authors and editors","Cowriting sprints and writer networking events"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ProWritingAid is a writing assistant built around the idea that good editing goes far beyond catching typos. Founded in the UK by Chris Banks, who built the first version to help himself finish a novel, the tool has grown into a suite of grammar, style, and readability reports used by fiction writers, bloggers, students, and business professionals alike.$q$, $q$Where many grammar checkers stop at flagging errors, ProWritingAid layers in dozens of specialized reports covering pacing, sentence variation, overused words, clichés, dialogue tags, and more. It pairs this depth with AI-driven rewrite suggestions and a Spark AI assistant for brainstorming and drafting, positioning it as much a writing coach as a proofreader.$q$, $q$The company has remained independently owned rather than venture-backed, which shows up in a product roadmap geared toward long-term writers rather than rapid enterprise expansion. It competes most directly with Grammarly, but leans harder into fiction and long-form manuscript editing than Grammarly's business-writing focus.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$who-prowritingaid-is-for$q$, $q$Who ProWritingAid Is For$q$, 2, ARRAY[$q$Novelists and self-published authors are the clearest fit. Reports like Pacing, Dialogue Tags, and the 90-author style comparison were built specifically for manuscript-length fiction, and integrations with Scrivener and other writing apps let authors edit inside the tools they already use.$q$, $q$Bloggers, freelance writers, and content marketers benefit from the readability and repeated-word reports, which help tighten prose for online audiences without needing a separate editor for every draft. Students and academic writers also use it to catch structural and clarity issues that basic spellcheck misses.$q$, $q$Non-native English speakers producing long-form content get real value from the depth of explanation behind each suggestion, since the tool explains the grammar rule rather than just applying a fix, which helps build language skill over time rather than just cleaning up a single document.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Anyone writing primarily in a language other than English should look elsewhere, since ProWritingAid only checks English text (across US, UK, Canadian, and Australian dialects) and has no plans announced for broader language support.$q$, $q$Users who need native mobile apps will be limited to the web editor on a phone, as ProWritingAid does not offer dedicated iOS or Android applications, unlike some competitors that prioritize on-the-go editing.$q$, $q$Teams needing centralized admin controls, SSO, or enterprise procurement features may find the plan structure too individual-writer-focused, and casual users who only want a lightweight spellchecker may find the volume of reports and suggestions more than they need.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of ProWritingAid is its report suite: grammar and spelling, style, readability, sentence structure, repeats, overused words, clichés and redundancies, and pacing, among others, each surfaced with explanations rather than silent corrections.$q$, $q$AI features add generative help on top of the analytical reports, including Rephrase for rewriting sentences in different tones, Spark AI for drafting and brainstorming, and Chapter Critique for higher-level manuscript feedback aimed at fiction writers.$q$, $q$Integrations extend the tool into Microsoft Word, Google Docs, Scrivener, and dozens of other apps and websites through Desktop Everywhere and browser extensions for Chrome, Firefox, and Edge, alongside a standalone web editor that works without installing anything.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('272fac60-438a-4487-9d22-a04e72fbaf3e', $q$the-prowritingaid-experience$q$, $q$The ProWritingAid Experience$q$, 2, ARRAY[$q$New users typically start in the web editor or browser extension, running a document through one report at a time. The interface highlights issues directly in the text and opens a side panel with explanations, which makes the learning curve gentler than it might sound given how many reports exist.$q$, $q$Because the reports are granular, first-time users often need a session or two to learn which ones matter most for their writing style; the tool rewards writers willing to read the explanations rather than just clicking through suggestions.$q$, $q$Premium and Premium Pro subscribers also get access to author-focused extras like live workshops, cowriting sessions, and community events, which shift the product from a pure editing tool toward a broader writing-community experience for serious authors.$q$]::text[], 4);
