INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Unified content calendar$q$, $q$Drag-and-drop calendar view for drafting, previewing, and scheduling posts across all connected social accounts in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Bulk scheduling$q$, $q$Upload and queue many posts at once via spreadsheet import or multi-file upload instead of scheduling one post at a time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Content recycling$q$, $q$Automatically re-queue evergreen posts on a recurring schedule so older content keeps reaching new followers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$RSS auto-posting$q$, $q$Turn blog or news feeds into scheduled social posts automatically, reducing manual content entry.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$AI writing assistant$q$, $q$Generate and refine captions, and get hashtag suggestions, using built-in AI tools on paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Team workspaces and approvals$q$, $q$Separate clients or brands into workspaces with custom roles and post approval workflows for team collaboration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Analytics and reporting$q$, $q$Track post and account performance with analytics dashboards and exportable reports on Business-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Media library with Canva integration$q$, $q$Store and reuse images and videos in a shared library, with direct Canva connectivity for design edits.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Browser extension$q$, $q$Capture articles, images, and links from anywhere on the web and send them straight into the Publer queue.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$API access$q$, $q$Business-tier customers can connect Publer to other tools and workflows through API access.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Generous free plan and low entry price compared to many scheduling competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Simple, easy-to-learn calendar interface with a short onboarding curve$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Content recycling and RSS automation reduce manual reposting work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Per-account, modular pricing lets teams scale costs to only the profiles they manage$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Responsive customer support and steady incremental feature updates$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Analytics and reporting are locked behind the Business plan and above$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Per-account pricing can add up quickly for teams managing many profiles$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Mobile apps are reported as less complete than the web dashboard$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Limited built-in video editing compared to dedicated creative tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$API documentation and some platform-specific features can lag behind the core scheduling experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Is Publer free to use?$q$, $q$Yes, Publer offers a free plan that supports a limited number of social accounts with capped scheduled posts and short post history; paid Professional and Business plans remove those limits and add more features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Which social networks does Publer support?$q$, $q$Publer supports Facebook, Instagram, X, LinkedIn, TikTok, Pinterest, YouTube, Google Business Profile, Threads, and several other networks, connected through a single dashboard.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$How is Publer priced?$q$, $q$Publer uses per-social-account and per-team-member pricing rather than flat seat tiers, so cost scales with the number of connected accounts and collaborators on Professional and Business plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Does Publer include analytics?$q$, $q$Basic account activity is visible on lower tiers, but detailed analytics, reporting, and competitor analysis are included starting on the Business plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Does Publer have a mobile app?$q$, $q$Yes, Publer offers Android and iOS apps in addition to its web dashboard, though some users find the mobile experience less full-featured than the browser version.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Solo creator content scheduling$q$, $q$An independent creator plans and queues posts for a few personal or brand accounts using the free or Professional plan.$q$, $q$Solopreneurs and independent creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Agency multi-client management$q$, $q$A social media agency organizes each client into a separate workspace, schedules content in bulk, and routes drafts through approval workflows before publishing.$q$, $q$Social media agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Small business marketing$q$, $q$A small business team schedules recurring promotions, recycles evergreen posts, and tracks performance on the Business plan's analytics dashboard.$q$, $q$Small and midsize business marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Nonprofit outreach scheduling$q$, $q$A nonprofit uses Publer's discounted plan to schedule awareness campaigns and donation drives across its social channels on a limited budget.$q$, $q$Nonprofits and charities$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["1 user and 1 workspace","3 social accounts (excludes X/Twitter)","10 scheduled posts per account","24-hour post history","25 saved drafts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Professional$q$, $q$$5/social account/month ($4/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Unlimited scheduled posts and drafts","Full post history","Unlimited workspaces and media storage","X/Twitter integration","Trending post suggestions and RSS automations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Business$q$, $q$$10/social account/month ($8/month billed annually)$q$, $q$Monthly or annual$q$, $q$["Everything in Professional","Unlimited AI writing prompts","Analytics insights and reports","Competitor analysis","Hashtag suggestions","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, $q$["All Business features","Higher-volume account and seat discounts","1:1 onboarding","Prioritized support","Higher daily posting limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Publer is a social media management and scheduling tool that lets individuals, small businesses, and agencies plan, publish, and track content across networks such as Facebook, Instagram, X, LinkedIn, TikTok, Pinterest, YouTube, Threads, and Google Business Profile from one dashboard. It grew out of a side project built in Albania to help a local business schedule Facebook posts, and it later evolved into a full publishing suite used by hundreds of thousands of accounts worldwide. The company remains headquartered in Tirana, Albania, and has stayed bootstrapped without outside venture funding throughout its growth.$q$, $q$The platform centers on a visual content calendar where users can draft, bulk-upload, and queue posts for multiple accounts and workspaces at once. Beyond simple scheduling, Publer adds recycling of evergreen content, RSS-based auto-posting, a shared media library, and a browser extension for capturing content from anywhere on the web, aiming to cover the full lifecycle of a social post rather than just the publish step. Paid tiers layer in AI-assisted captions, analytics, and API access on top of that core workflow.$q$, $q$As a bootstrapped company, Publer has positioned itself as a lower-cost alternative to larger social media suites, using a modular, per-account pricing structure instead of flat seat-based tiers. That approach, combined with a generous free tier, has made it a common pick for solo creators and lean marketing teams comparing tools like Buffer, Hootsuite, and Later. Nonprofits also receive a published lifetime discount on any paid plan, reinforcing the company's budget-conscious positioning.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$who-publer-is-for$q$, $q$Who Publer Is For$q$, 2, ARRAY[$q$Publer suits solopreneurs, freelancers, and independent creators who manage a handful of social profiles and want a straightforward scheduling calendar without paying for an enterprise-grade suite. The free plan and low-cost Professional tier make it approachable for people just starting to formalize their posting workflow across a few networks.$q$, $q$Small and midsize marketing teams and social media agencies are another strong fit, particularly those juggling multiple client accounts. The Business plan's workspace separation, approval workflows, and per-account pricing let agencies scale the number of managed profiles up or down without committing to a large fixed monthly seat cost, which is useful when client rosters change frequently throughout the year.$q$, $q$Nonprofits and budget-conscious organizations also gravitate toward Publer because of its published discount for registered charities and its relatively transparent pricing calculator. Content-heavy creators who repost evergreen material, run RSS-driven blogs, or need a Canva-connected media library will likely get the most out of its recycling and automation features.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with dozens of brand accounts and strict procurement or compliance requirements may find Publer's self-serve, contact-sales-only Enterprise tier less mature than the dedicated enterprise programs offered by bigger competitors. Organizations that need deep platform-specific paid social integrations, social listening, or influencer management tools may also outgrow what Publer currently offers.$q$, $q$Teams that rely heavily on in-app video editing, advanced creative asset generation, or sophisticated cross-channel attribution reporting may find Publer's built-in tools comparatively basic. Users expecting robust native analytics out of the free or entry-level Professional plan will be disappointed, since analytics and reporting are reserved for the Business tier and above.$q$, $q$Because pricing scales per connected social account rather than a single flat fee, businesses managing a very large number of profiles should model their costs carefully; the per-account model can become more expensive than flat-rate competitors at high volume. Anyone needing a single-vendor solution with dedicated account management from day one may prefer a larger, VC-backed platform instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Publer offers a unified content calendar for drafting, previewing, and scheduling posts across supported networks, along with bulk scheduling for uploading and queuing many posts at once. Content recycling lets evergreen posts automatically repeat on a set cadence, while RSS automations can turn blog or news feeds into scheduled social updates without manual copy-pasting.$q$, $q$Collaboration features include multiple workspaces, custom user roles, and post approval workflows, which help agencies and teams coordinate client or brand content before it goes live. Paid plans add an AI writing assistant for captions and hashtag suggestions, a shared media library with Canva integration, and a browser extension for saving content directly into the queue.$q$, $q$Business-tier customers gain analytics and reporting dashboards, competitor analysis, and API access for building custom integrations. Publer is also available as a web application plus Android and iOS mobile apps, so scheduling, approvals, and quick edits can happen from a phone as well as a desktop browser.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e279aac8-93be-4884-86b3-544687f01909', $q$the-publer-experience$q$, $q$The Publer Experience$q$, 2, ARRAY[$q$Day to day, Publer's interface is built around a calendar and a queue, and most reviewers describe the learning curve as low: connecting an account, drafting a post, and scheduling it across several networks typically takes only a few clicks. The layout keeps drafts, scheduled posts, and published history in clearly separated views, so switching between planning and reviewing what already went live feels straightforward.$q$, $q$Customer support is frequently cited as responsive, and the product ships incremental updates rather than large overhauls, which keeps the workflow familiar over time. Because pricing is calculated per social account and per team member, users can start small on the free or Professional plan and add accounts only as their needs grow.$q$, $q$The trade-off some users report is that the mobile apps feel less complete than the web dashboard, and that deeper analytics or API documentation can lag behind the scheduling experience itself. Overall, the day-to-day experience favors simplicity and cost control over the breadth of features found in larger, more expensive social suites, which suits teams that prioritize predictable pricing over an extensive feature checklist.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e279aac8-93be-4884-86b3-544687f01909', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
