INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$CoreXM Survey Builder$q$, $q$Advanced survey creation with complex branching logic, quotas, randomization, and support for many question types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$XM Directory$q$, $q$Centralized contact and panel management for organizing respondent lists, segments, and communication preferences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Text iQ / AI Analytics$q$, $q$AI-assisted text and sentiment analysis that automatically categorizes open-text feedback and surfaces themes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Dashboards and Reporting$q$, $q$Role-based dashboards for tracking KPIs such as NPS and eNPS and sharing results across the organization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$CX Solutions$q$, $q$Purpose-built modules for journey mapping, case management, and frontline customer experience programs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$EX Solutions$q$, $q$Employee lifecycle and engagement survey programs covering onboarding, pulse surveys, and exit feedback.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Enterprise Integrations$q$, $q$Prebuilt connections to CRM, helpdesk, and collaboration tools such as Salesforce and Slack.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Multilingual Survey Delivery$q$, $q$Survey translation and delivery across a wide range of languages for global research programs.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Offline Mobile App$q$, $q$A mobile app that supports offline data collection for field research and in-person surveys.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Template Library$q$, $q$A large library of prebuilt survey and project templates to speed up study design.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Powerful, enterprise-grade research and survey logic capabilities$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Extensive customization, branching, and quota/randomization options$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$AI-assisted text and sentiment analytics reduce manual coding work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Wide integration ecosystem with CRM, helpdesk, and collaboration tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Robust security, compliance, and administrative controls suited to large organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Pricing is not publicly transparent and typically requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Can be expensive relative to lightweight survey tools for smaller teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Steep learning curve given the depth of features and configuration options$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Free account tier is limited in active surveys and response volume$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Enterprise procurement and onboarding cycles can be slow compared to self-serve tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Does Qualtrics have a free plan?$q$, $q$Yes. Qualtrics offers a limited free account with a cap on active surveys and responses, and it can be temporarily upgraded to a 30-day trial of a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$How much does Qualtrics cost?$q$, $q$Most Qualtrics enterprise suites (CX, EX, and Strategic Research) are custom-quoted based on modules, volume, and organization size, so pricing is not published; a self-service Strategic Research plan can also be purchased online.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$What is Qualtrics used for?$q$, $q$Qualtrics is used for customer experience programs, employee experience and engagement surveys, academic and market research, and general-purpose survey data collection and analysis.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Is Qualtrics only for large enterprises?$q$, $q$The core enterprise suites target large organizations, but Qualtrics also offers a free account and a self-service paid plan that make it usable by students, researchers, and smaller teams.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Does Qualtrics use AI?$q$, $q$Yes. Qualtrics includes AI-assisted features such as Text iQ for automated theme and sentiment analysis of open-text survey responses.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Customer Experience Programs$q$, $q$Tracking NPS, satisfaction, and customer journeys to identify and close experience gaps across touchpoints.$q$, $q$CX teams and customer insights leaders at mid-size to large companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Employee Experience and Engagement$q$, $q$Running onboarding, pulse, engagement, and exit surveys to measure and improve the employee lifecycle.$q$, $q$HR and people-operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Academic and Market Research$q$, $q$Designing statistically rigorous surveys with advanced logic, panels, and quotas for research studies.$q$, $q$Academic researchers, students, and market research firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Product and Concept Feedback$q$, $q$Gathering structured feedback on product concepts, features, and messaging from customers or panels.$q$, $q$Product and UX research teams within larger organizations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Free Account$q$, $q$$0$q$, $q$N/A$q$, $q$["Up to 3 active surveys","Up to 500 responses per user","Unlimited inactive surveys","Optional 30-day trial upgrade"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$Strategic Research (Self-Service)$q$, $q$Custom$q$, $q$Monthly or annual$q$, $q$["Online purchase without a sales call","Expanded survey and response limits","Core survey logic and reporting tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$CoreXM / CX / EX Enterprise$q$, $q$Custom quote$q$, $q$Annual contract$q$, $q$["Full CX, EX, or Strategy & Research suite access","Volume-based pricing on interactions or employees","Dedicated account and implementation support","Advanced integrations and admin controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Qualtrics is an experience management (XM) platform, founded in 2002 in Provo, Utah, that helps organizations collect and analyze feedback across customer, employee, product, and brand touchpoints. What began as an academic survey tool built by founder Ryan Smith and his father grew into one of the most widely used enterprise research platforms in the world, with offices across North America, Europe, and Asia-Pacific.$q$, $q$In 2019 Qualtrics was acquired by SAP in a deal valued at roughly $8 billion, then spun back out as an independent public company following an IPO in early 2021. Today Qualtrics operates as a standalone company again, continuing to expand its Experience Management Platform across customer experience, employee experience, and strategic and market research use cases.$q$, $q$The platform is organized around three core suites: XM for Customer Experience, XM for Employee Experience, and XM for Strategy and Research, all built on top of CoreXM, its foundational survey and data-collection engine. Pricing across these suites is not published publicly and is instead quoted based on the specific modules licensed, response or interaction volume, and the size of the purchasing organization. Alongside its enterprise suites, Qualtrics also maintains a limited free account tier and a paid self-service research plan that can be purchased online, giving individual researchers and smaller teams a lower-commitment way to try the platform before considering a full enterprise contract.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$who-qualtrics-is-for$q$, $q$Who Qualtrics Is For$q$, 2, ARRAY[$q$Qualtrics is built primarily for larger organizations - enterprises, universities, government agencies, and market research firms - that need to run structured, statistically rigorous surveys and feedback programs at scale. Dedicated CX and EX teams that must track metrics like NPS, employee engagement, and brand health over time are a core audience for the platform.$q$, $q$Market researchers and academic researchers also use Qualtrics heavily, thanks to its advanced survey logic, panel management, and statistical analysis tools that go well beyond typical online form builders. Its free account option makes it accessible to students, faculty, and individual researchers who need a serious research-grade tool without committing to an enterprise contract.$q$, $q$Product and UX teams within larger companies also adopt Qualtrics for structured feedback loops, concept testing, and customer research, particularly when that feedback needs to integrate with other enterprise systems like Salesforce, Slack, or internal dashboards. Organizations with dedicated budget for research operations, a need for auditability and compliance, and multiple stakeholders needing self-serve access to results tend to be well suited to the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, solo founders, and teams that just need a quick, inexpensive survey or form tool are likely to find Qualtrics more platform than they actually need. Its enterprise-oriented licensing model, sales-driven onboarding process, and modular pricing structure are built for organizations with dedicated budget and procurement processes, not casual or one-off survey use.$q$, $q$Anyone who wants transparent, self-serve pricing they can see and purchase online without a sales conversation will likely be frustrated, since most paid tiers of Qualtrics require a custom quote and a conversation with a sales representative rather than a simple checkout flow like many lighter-weight survey tools offer.$q$, $q$Teams with a short runway to get a first survey live may also find the learning curve steep, since Qualtrics's extensive customization options, branching logic, and dashboarding tools take real time to learn relative to lightweight survey tools. Organizations that only need basic single-survey functionality may be better served by a simpler, lower-cost alternative.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Qualtrics's CoreXM survey builder supports advanced question types, branching logic, quotas, randomization, and multilingual survey delivery, letting research teams design complex studies rather than simple forms. Its XM Directory functions as a contact and panel management system, allowing organizations to manage respondent lists, segments, and communication preferences from a central location.$q$, $q$Built-in analytics include Text iQ and other AI-assisted tools that automatically categorize open-text feedback, detect sentiment, and surface themes, reducing the manual work of coding qualitative responses by hand. Dashboards and reporting tools let teams build role-based views, track KPIs like NPS or eNPS over time, and share results with stakeholders outside the platform itself.$q$, $q$Specialized modules extend CoreXM into full CX and EX solutions, offering journey mapping, case management, and employee lifecycle survey programs, while a broad library of integrations connects Qualtrics to CRM, helpdesk, and collaboration tools such as Salesforce and Slack. An offline mobile app and an extensive template library round out the feature set for field research and faster survey creation.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b111844-9cfa-4a96-813d-555779600f9d', $q$the-qualtrics-experience$q$, $q$The Qualtrics Experience$q$, 2, ARRAY[$q$Using Qualtrics feels distinctly enterprise-grade: the interface is dense with options, and new users typically need onboarding, documentation, or a Qualtrics account team to get the most out of its logic, reporting, and integration capabilities. For teams running only one or two straightforward surveys, this depth can feel like overkill relative to what they actually need.$q$, $q$For organizations running ongoing CX, EX, or research programs, that same depth becomes the appeal, since the platform can handle everything from a single ad hoc survey to a company-wide employee engagement program with role-based dashboards and automated alerts. Qualtrics also invests heavily in training resources, certifications, and its Basecamp user conference to help customers extract more value from the platform over time.$q$, $q$Overall, the experience trades simplicity for power and configurability: expect a longer setup and learning period than a lightweight survey tool, offset by far greater depth in logic, analytics, and enterprise integrations once teams are up and running. Support quality and onboarding attentiveness tend to scale with contract size, which is fairly typical of enterprise SaaS products in this category.$q$]::text[], 4);
