INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', $q$Drag-and-Drop Survey Builder$q$, $q$Build surveys visually with dozens of question types, custom branding, and reusable templates.$q$, 0);
