INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8654c2ee-c1a5-4a9e-82aa-9243994e337c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Invoicing and estimates$q$, $q$Create, send, and track customer invoices and quotes, with automatic reminders for unpaid balances.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Expense and receipt tracking$q$, $q$Capture receipts and categorize expenses, including automatic import from connected bank and credit card feeds.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Bank feed reconciliation$q$, $q$Connect financial accounts to automatically import and match transactions against the books.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Financial reporting$q$, $q$Generate profit and loss, balance sheet, cash flow, and other standard reports for owners, lenders, and tax preparers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Payroll add-on$q$, $q$Run payroll, calculate taxes, and manage direct deposit through an integrated Intuit payroll subscription.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Multi-user roles and accountant access$q$, $q$Assign different permission levels to employees, bookkeepers, and accountants working in the same company file.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Mileage tracking$q$, $q$Automatically log business mileage via the mobile app for expense reporting and tax deductions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Inventory management$q$, $q$Track quantities on hand, cost of goods sold, and reorder points for product-based businesses on eligible plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Project and class tracking$q$, $q$Track income and expenses by project, location, or class to see profitability across different parts of the business.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$App marketplace and API access$q$, $q$Integrate with e-commerce, point-of-sale, and CRM apps, or build custom connections through Intuit's developer API.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Wide adoption among small businesses and accountants, making it easy to find bookkeepers already familiar with the platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Scales across four plan tiers, so pricing and features can grow with the business$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Strong bank feed automation and standard financial reporting for owners and tax preparers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Mobile apps for iOS and Android cover invoicing, receipt capture, and mileage tracking on the go$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Large ecosystem of third-party integrations and an API for connecting to other business tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Monthly subscription costs add up once payroll, payments, or higher tiers are included$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Has a learning curve for users without prior bookkeeping or accounting experience$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Some users report inconsistent customer support response quality$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Lower-tier plans limit the number of users and access to features like inventory or project tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Pricing has increased over time, which has drawn criticism from long-time subscribers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$What is the difference between QuickBooks Online and QuickBooks Desktop?$q$, $q$QuickBooks Online is a cloud-based, browser-accessible subscription product with continuous updates, while QuickBooks Desktop is locally installed software typically purchased as an annual license, often preferred by users who want offline access or more advanced industry-specific features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Can I migrate existing data from QuickBooks Desktop to QuickBooks Online?$q$, $q$Yes, Intuit provides a built-in data conversion tool to import company files, including lists, transactions, and balances, from QuickBooks Desktop into QuickBooks Online, though some complex data may require manual review after migration.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Does QuickBooks Online include payroll?$q$, $q$Payroll is not included in the core plans by default; it is offered as a separate QuickBooks Payroll add-on subscription that integrates directly with the accounting data.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Is there a mobile app for QuickBooks Online?$q$, $q$Yes, Intuit offers QuickBooks Online mobile apps for iOS and Android that support invoicing, expense and receipt capture, mileage tracking, and viewing account balances.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Can my accountant access my QuickBooks Online account?$q$, $q$Yes, QuickBooks Online supports dedicated accountant user access, allowing an external bookkeeper or CPA to log in with their own credentials and permissions to review or adjust the books remotely.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Freelancer and solopreneur invoicing$q$, $q$A single-person consultancy uses QuickBooks Online Simple Start to send professional invoices, track client payments, and monitor basic expenses without hiring dedicated bookkeeping staff.$q$, $q$Freelancers and independent contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Retail and e-commerce inventory tracking$q$, $q$A small retailer connects QuickBooks Online to its point-of-sale or e-commerce platform to track inventory levels, cost of goods sold, and sales tax across multiple sales channels.$q$, $q$Small retail and e-commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Professional services project billing$q$, $q$An agency or consulting firm uses class and project tracking to monitor profitability on individual client engagements and bill time and expenses accurately.$q$, $q$Agencies, consultancies, and professional service firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Growing business with an outside bookkeeper$q$, $q$A company with a handful of employees uses the Plus or Advanced plan to give an external accountant restricted access, run payroll, and generate the financial reports needed for tax filing and loan applications.$q$, $q$Small businesses working with external accountants or bookkeepers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Simple Start$q$, $q$Approximately $35/month (US, before promotions)$q$, $q$Monthly$q$, $q$["Income and expense tracking","Invoicing and estimates","Basic financial reports","Receipt capture","One user plus accountant access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Essentials$q$, $q$Approximately $65/month (US, before promotions)$q$, $q$Monthly$q$, $q$["Everything in Simple Start","Bill management","Multiple users (typically up to 3)","Time tracking","Multi-currency support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Plus$q$, $q$Approximately $99/month (US, before promotions)$q$, $q$Monthly$q$, $q$["Everything in Essentials","Inventory tracking","Project profitability tracking","Budgeting tools","Additional users (typically up to 5)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$Advanced$q$, $q$Approximately $235/month (US, before promotions)$q$, $q$Monthly$q$, $q$["Everything in Plus","Expanded user limits (typically up to 25)","Custom user permissions and roles","Advanced reporting and dashboards","Dedicated account support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuickBooks Online is Intuit's cloud-based accounting platform built for small and mid-sized businesses. It brings invoicing, expense tracking, bank reconciliation, and financial reporting into a single subscription-based web application, replacing the older locally installed desktop model with anytime, anywhere access from a browser or mobile device. Data syncs automatically, and feature updates roll out continuously rather than through periodic paid upgrades.$q$, $q$The product is owned by Intuit, a financial software company founded in 1983 and headquartered in Mountain View, California. QuickBooks Online sits inside a broader Intuit ecosystem that also includes TurboTax, Mailchimp, and Credit Karma, and it has become one of the most widely used accounting tools among small businesses and the bookkeepers and accountants who support them.$q$, $q$QuickBooks Online is organized into tiered monthly plans, currently Simple Start, Essentials, Plus, and Advanced, so a solo freelancer and a company with dozens of employees can each choose a feature set and price point that fits their complexity. Add-ons for payroll, payment processing, and time tracking extend the core product as a business grows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$who-quickbooks-online-is-for$q$, $q$Who QuickBooks Online Is For$q$, 2, ARRAY[$q$QuickBooks Online is best suited to small business owners who need real bookkeeping and financial reporting but don't want to hire a full-time accountant to run it. Freelancers, retailers, service providers, and small teams use it to send invoices, track expenses, reconcile bank accounts, and generate the profit-and-loss and balance sheet reports that lenders, tax preparers, and investors typically ask for.$q$, $q$It is also a strong fit for businesses that already work with an outside bookkeeper or CPA, since QuickBooks Online supports multiple user roles and gives accountants a way to log in remotely, review transactions, and make adjustments without exchanging files. Intuit's network of QuickBooks ProAdvisors means it is often the accounting system an incoming bookkeeper already knows.$q$, $q$Businesses that need inventory tracking, project profitability reporting, or payroll integrated with the same ledger tend to gravitate toward the higher Plus and Advanced tiers, which unlock more users, more detailed reporting, and features like batch invoicing. Companies with straightforward needs, such as a single-person consultancy, can typically operate comfortably on the entry-level Simple Start plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$QuickBooks Online may not be the right choice for very early-stage businesses or side projects with minimal transaction volume, since the monthly subscription cost, plus optional add-ons like payroll or payments, can feel disproportionate to a small operation's bookkeeping needs. Free or lower-cost invoicing tools may cover that use case more economically.$q$, $q$Larger organizations with complex multi-entity consolidation, advanced manufacturing workflows, or heavy customization requirements often outgrow QuickBooks Online and move to enterprise resource planning systems, since even the Advanced plan has practical ceilings on user counts, chart-of-accounts complexity, and industry-specific workflows compared with dedicated ERP software.$q$, $q$Businesses that specifically prefer owning a one-time-purchase, locally installed desktop application rather than an ongoing cloud subscription may be better served by QuickBooks Desktop or another on-premises accounting package, since QuickBooks Online requires an internet connection and recurring monthly payments rather than a single license fee.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, QuickBooks Online covers customer invoicing and payment collection, expense and receipt tracking, bank and credit card feed connections with automatic transaction categorization, and standard financial reports such as profit and loss, balance sheet, and cash flow statements. These form the backbone of day-to-day bookkeeping for most subscribers.$q$, $q$Beyond the basics, the platform adds mileage tracking, sales tax calculation, estimates and quotes, multiple user roles with permission controls, and, on higher tiers, inventory management and project or class-based profitability tracking. Payroll, QuickBooks Payments for card and bank transfers, and time tracking are available as integrated add-ons rather than baked into every plan.$q$, $q$QuickBooks Online also connects to a large marketplace of third-party apps for e-commerce, point of sale, CRM, and industry-specific workflows, and exposes an API that developers and integration platforms use to sync data with other business systems, which is a major reason accountants and software vendors build around it as a hub.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', $q$the-quickbooks-online-experience$q$, $q$The QuickBooks Online Experience$q$, 2, ARRAY[$q$Day to day, QuickBooks Online presents a dashboard summarizing bank balances, outstanding invoices, and recent expenses, with navigation organized around banking, sales, expenses, and reports. New users typically spend their first sessions connecting bank feeds and categorizing a backlog of transactions, after which the software largely automates ongoing reconciliation.$q$, $q$The web app is complemented by iOS and Android mobile apps that let users capture receipts, send invoices, and check account balances on the go, which many small business owners rely on more than the desktop browser experience for quick tasks between client visits or jobs.$q$, $q$Because QuickBooks Online is accounting software rather than a simple invoicing tool, there is a learning curve for owners without bookkeeping background, and the interface can feel dense compared with lighter-weight alternatives. Most users offset this by working with an accountant who already knows the platform or by using Intuit's built-in guidance and support resources.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9e200cb1-a048-4c0a-ac15-ece1a517f982', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
