INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Paraphraser$q$, $q$Rewrites sentences in multiple modes (Standard, Fluency, Formal, Creative, and more) with a synonym slider to control how much wording changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Grammar Checker$q$, $q$Flags spelling, punctuation, and grammar errors and suggests corrections as you write.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Plagiarism Checker$q$, $q$Scans submitted text against web and academic sources to highlight matching or unoriginal passages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Summarizer$q$, $q$Condenses long articles or documents into key-point or paragraph-style summaries.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Citation Generator$q$, $q$Formats references and bibliographies automatically in styles such as APA, MLA, and Chicago.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$AI Content Detector$q$, $q$Estimates the likelihood that a piece of text was generated by AI.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Co-Writer$q$, $q$A document workspace for drafting, organizing, and editing longer pieces of writing in one place.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Translator$q$, $q$Translates text across dozens of languages while aiming to preserve tone and meaning.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Browser and Word Extensions$q$, $q$Chrome extension and Microsoft Word add-in bring grammar and paraphrasing suggestions directly into other apps.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Mobile Keyboard Apps$q$, $q$iOS and Android keyboard apps apply paraphrasing and grammar checks while typing on mobile devices.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free plan is genuinely usable, not just a limited demo$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Paraphraser offers multiple tone and style modes with fine control over rewrite intensity$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Works across the web app, Chrome extension, Word add-in, and mobile keyboard under one subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Bundles grammar, summarizing, citation, and plagiarism tools alongside paraphrasing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Simple, low-friction interface with a short learning curve$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free tier limits input length and available paraphrasing modes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Heavy paraphrasing can alter nuance or meaning in technical or specialized writing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Not designed for generating long-form content from scratch like dedicated AI writing platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Overreliance on paraphrasing may raise academic integrity concerns in some institutions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Teams plan offers fewer enterprise admin and compliance controls than larger writing suites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Is QuillBot free to use?$q$, $q$Yes, QuillBot offers a free plan with basic paraphrasing, grammar checking, and other tools, though with limits on input length and available modes. A paid Premium plan removes those limits and unlocks additional features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Who owns QuillBot?$q$, $q$QuillBot was founded in 2017 and acquired by Course Hero in 2021. Course Hero later rebranded as Learneo, which also owns Scribbr, CliffsNotes, LanguageTool, and Symbolab.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Does QuillBot have a plagiarism checker?$q$, $q$Yes, QuillBot includes a Plagiarism Checker that compares submitted text against web and academic sources to flag overlapping or unoriginal content.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Can QuillBot be used on mobile devices?$q$, $q$Yes, QuillBot offers keyboard apps for iOS and Android that apply paraphrasing and grammar suggestions while typing, in addition to the web app and browser extension.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Is QuillBot's paraphrased text detectable as AI-written?$q$, $q$It can be, depending on the AI detection tool and how heavily the text is rewritten. QuillBot also offers its own AI Content Detector, but users should treat paraphrasing as an editing aid rather than a guaranteed way to avoid detection.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Academic essay revision$q$, $q$Rephrasing source material, formatting citations, and running a plagiarism check before submitting coursework.$q$, $q$Students and academic writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Grammar and tone cleanup for professional emails$q$, $q$Using the Chrome extension or Word add-in to catch grammar mistakes and adjust tone in daily business writing.$q$, $q$Professionals and office workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Content rewriting for blogs and marketing copy$q$, $q$Rephrasing drafts to vary wording and improve readability before publishing.$q$, $q$Content marketers and bloggers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Writing support for non-native English speakers$q$, $q$Getting quick grammar corrections and clearer phrasing suggestions while composing English text.$q$, $q$ESL learners and non-native English speakers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Basic Paraphraser with limited modes","Basic Grammar Checker","Limited input length","Access to web app, extension, and mobile keyboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium (Monthly)$q$, $q$$19.95/month$q$, $q$Monthly$q$, $q$["All paraphrasing modes unlocked","Unlimited grammar checking","Longer input length","Access to Summarizer, Citation Generator, and Plagiarism Checker"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium (Annual)$q$, $q$$8.33/month, billed at $99.95/year$q$, $q$Annual$q$, $q$["All Premium features included","Lower effective monthly cost","All paraphrasing modes unlocked","Unlimited grammar checking"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Student$q$, $q$$6.25/month (verified students)$q$, $q$Annual$q$, $q$["Full Premium feature set","Discounted rate for verified students","Citation Generator and Plagiarism Checker included","All paraphrasing modes unlocked"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuillBot is an AI-powered writing assistant built around paraphrasing, grammar correction, and a set of adjacent writing tools such as a summarizer, citation generator, plagiarism checker, and AI content detector. It was founded in 2017 by a small team of computer science students and grew quickly on the strength of its paraphrasing engine, which rewrites sentences while preserving meaning and letting users dial in a preferred tone or level of formality.$q$, $q$In 2021, QuillBot was acquired by Course Hero, which later rebranded its parent company as Learneo, a group that also owns Scribbr, CliffsNotes, LanguageTool, and Symbolab. Under Learneo, QuillBot expanded from a single paraphrasing web tool into a broader writing suite available through its website, a Chrome browser extension, a Microsoft Word add-in, and mobile keyboard apps for iOS and Android, all tied to one subscription.$q$, $q$The product sits in the same general category as Grammarly and ProWritingAid but is best known specifically for paraphrasing quality and academic-adjacent tools like citation formatting and plagiarism checking. Its freemium model gives casual users a genuinely usable free tier, while QuillBot Premium unlocks longer inputs, additional paraphrasing modes, and unlimited use of the grammar and other writing tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$who-quillbot-is-for$q$, $q$Who QuillBot Is For$q$, 2, ARRAY[$q$QuillBot is a strong fit for students and academic writers who need to rephrase source material, format citations, and check drafts for grammar and unintentional plagiarism before submission. Its citation generator and plagiarism checker are tailored to essay and research-paper workflows, and the paraphraser's tone and mode controls help with rewriting dense academic language into clearer sentences.$q$, $q$It also appeals to non-native English speakers and ESL learners who want quick, low-friction help rephrasing sentences and catching grammar mistakes without the more complex tone-and-style tooling found in enterprise writing suites. Professionals writing routine emails, internal documents, or short marketing copy can similarly use it as a fast rewriting and proofreading layer inside their existing apps via the browser extension and Word add-in.$q$, $q$Freelance writers, bloggers, and small content teams who need occasional rewriting and summarizing support, rather than a full brand-voice or long-form generation platform, are a good match too. Because the free plan is usable on its own, casual or infrequent users can rely on QuillBot without committing to a paid subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need enterprise-grade style guides, brand voice enforcement, or large-scale long-form AI content generation are usually better served by dedicated content platforms or Grammarly Business, since QuillBot's feature set is centered on rewriting and proofreading rather than generating full articles from scratch at scale.$q$, $q$Students or professionals who need to demonstrate strict academic integrity should be cautious about leaning on paraphrasing tools as a substitute for original writing; some institutions flag heavily AI-rephrased text, so QuillBot works best as an editing aid rather than a way to disguise unoriginal work.$q$, $q$Organizations that require extensive admin controls, single sign-on, granular compliance settings, or large multi-department rollouts may also find QuillBot's Teams offering limited compared to purpose-built enterprise writing or security platforms, since it is designed for small groups rather than large-scale corporate deployment.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of QuillBot is its Paraphraser, which offers multiple rewriting modes (such as Standard, Fluency, Formal, and Creative) plus a synonym slider to control how aggressively wording changes, alongside a Grammar Checker that flags spelling, punctuation, and grammar issues with suggested fixes.$q$, $q$Beyond rewriting, QuillBot includes a Summarizer that condenses long text into key points or paragraph summaries, a Citation Generator that formats references in styles like APA, MLA, and Chicago, and a Plagiarism Checker that compares submitted text against web and academic sources to flag overlap.$q$, $q$Rounding out the suite are an AI Content Detector for estimating whether text was AI-generated, a Co-Writer workspace for drafting and organizing longer documents, a Translator supporting dozens of languages, and distribution through a Chrome extension, Microsoft Word add-in, and mobile keyboard apps so the tools travel with the user across platforms.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$the-quillbot-experience$q$, $q$The QuillBot Experience$q$, 2, ARRAY[$q$Day to day, QuillBot presents a clean, minimal interface: paste text into the Paraphraser or Grammar Checker and see suggestions appear inline, with the Chrome extension and Word add-in surfacing the same corrections directly inside Gmail, Google Docs, LinkedIn, or Word documents without switching tabs.$q$, $q$The free plan covers shorter inputs and a limited set of paraphrasing modes, which is enough for occasional use, while Premium removes those caps, unlocks every paraphrasing mode, and adds unlimited use of the grammar, summarizing, and other writing tools, along with faster processing on longer passages.$q$, $q$Overall, the experience favors speed and simplicity over deep customization: there is little setup required, the learning curve is shallow, and most users are productive within minutes, though writers wanting fine-grained brand-voice control or long-form drafting from a blank page may find the toolset narrower than an all-in-one AI writing platform.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
